parameters.jsCode:
const all = $input.all();
const stageCount = {};
const tempCount = { hot: 0, warm: 0, cold: 0 };
let totalScore = 0;
all.forEach(item => {
  const f = item.json.fields;
  const stage = f.Stage || 'New';
  stageCount[stage] = (stageCount[stage] || 0) + 1;
  const temp = (f.Temperature || 'cold').toLowerCase();
  if (tempCount[temp] !== undefined) tempCount[temp]++;
  totalScore += (f.Score || 0);
});
const total = all.length;
return [{ json: {
  total_leads: total,
  pipeline: {
    new: stageCount['New'] || 0,
    qualified: stageCount['Qualified'] || 0,
    contacted: stageCount['Contacted'] || 0,
    replied: stageCount['Replied'] || 0,
    interested: stageCount['Interested'] || 0,
    booked: stageCount['Booked'] || 0,
    closed: stageCount['Closed'] || 0
  },
  temperature: tempCount,
  avg_score: total > 0 ? Math.round(totalScore / total) : 0,
  conversion_rate: total > 0 ? Math.round(((stageCount['Interested'] || 0) + (stageCount['Booked'] || 0) + (stageCount['Closed'] || 0)) / total * 100) : 0,
  timestamp: new Date().toISOString()
}}];

const sd = $getWorkflowStaticData('global');
if (!sd.runReport) {
  sd.runReport = { leads_captured: [], leads_duplicated: [], emails_sent: [] };
}

const norm   = $('Normalize Lead Data1').item.json;
const ai     = $('AI Lead Qualifier1').item.json.output;
const email  = $('Generate Outreach Email1').item.json.output;
const sentTo = norm.email || 'kartik6jakhar@gmail.com';

sd.runReport.leads_captured.push({
  name:               norm.name        || 'Unknown',
  title:              norm.title       || '',
  company:            norm.company     || '',
  profile_url:        norm.profile_url || '',
  email:              sentTo,
  score:              ai.score,
  priority:           ai.priority,
  temperature:        ai.temperature,
  category:           ai.category,
  pain_point:         ai.pain_point    || '',
  stage:              'Contacted',
  email_sent:         true,
  email_subject:      email?.subject   || '',
  airtable_record_id: $('Store Lead in Airtable1').item.json.id || ''
});

sd.runReport.emails_sent.push({
  name:    norm.name || 'Unknown',
  email:   sentTo,
  subject: email?.subject || ''
});

return [{ json: { _loopContinue: true } }];

