});

return [{ json: { _loopContinue: true } }];

const sd = $getWorkflowStaticData('global');
if (!sd.runReport) {
  sd.runReport = { leads_captured: [], leads_duplicated: [], emails_sent: [] };
}

const norm = $('Normalize Lead Data1').item.json;

sd.runReport.leads_duplicated.push({
  name:        norm.name        || 'Unknown',
  profile_url: norm.profile_url || '',
  email:       norm.email       || ''
});

return [{ json: { _loopContinue: true } }];

const sd     = $getWorkflowStaticData('global');
const report = sd.runReport || { leads_captured: [], leads_duplicated: [], emails_sent: [] };

const captured   = report.leads_captured   || [];
const duplicated = report.leads_duplicated || [];
const emailsSent = report.emails_sent      || [];

const summary = {
  status: 'completed',
  run_at: new Date().toISOString(),
  stats: {
    total_incoming:   captured.length + duplicated.length,
    leads_captured:   captured.length,
    leads_duplicated: duplicated.length,
    emails_sent:      emailsSent.length,
    by_temperature: {
      hot:  captured.filter(l => l.temperature === 'hot').length,
      warm: captured.filter(l => l.temperature === 'warm').length,
      cold: captured.filter(l => l.temperature === 'cold').length
    },
    by_stage: {
      contacted: captured.filter(l => l.stage === 'Contacted').length,
      new_only:  captured.filter(l => l.stage === 'New').length
    }
  },
  emails_sent_to: emailsSent.map(e => ({
    name:    e.name,
    email:   e.email,
    subject: e.subject
  })),
  leads: captured.map(l => ({
    name:        l.name,
    title:       l.title,
    company:     l.company,
    profile_url: l.profile_url,
    email:       l.email,
    score:       l.score,
    priority:    l.priority,
    temperature: l.temperature,
    category:    l.category,
    pain_point:  l.pain_point,
    stage:       l.stage,
    email_sent:  l.email_sent,
    record_id:   l.airtable_record_id
  })),
  duplicates_skipped: duplicated.map(d => ({
    name:        d.name,
    profile_url: d.profile_url
  }))
};

// Reset for next run
sd.runReport = { leads_captured: [], leads_duplicated: [], emails_sent: [] };

return [{ json: summary }];
